<!doctype html><html lang="pl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Neon Loop Station <?=htmlspecialchars($version)?></title><link rel="stylesheet" href="assets/style.css"></head><body>
