<section class="panel master-grid"><label>BPM <input id="bpm" type="number" min="55" max="220" value="120"></label><label>Kroki <select id="steps"><option>16</option><option>32</option></select></label><label>Swing <input id="swing" type="range" min="0" max="0.45" step="0.01" value="0.08"></label><label>Master <input id="masterVol" type="range" min="0" max="1" step="0.01" value="0.85"></label><label>Preset <select id="presetSelect"></select></label><button id="saveProjectBtn">Zapisz projekt</button><button id="loadProjectBtn">Wczytaj projekt</button><button id="clearBtn">Wyczyść</button></section>
